#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    int c = getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char line[256];
        while (fgets(line, sizeof(line), stdin)) {
            size_t len = strlen(line);
            if (len && line[len-1] == '\n') line[--len] = '\0';
            // trim leading spaces
            char *start = line;
            while (*start && isspace((unsigned char)*start)) ++start;
            // trim trailing spaces
            char *end = start + strlen(start) - 1;
            while (end >= start && isspace((unsigned char)*end)) *end-- = '\0';
            // lower‑case copy for sentinel check
            char lowered[256];
            size_t i;
            for (i = 0; start[i]; ++i) lowered[i] = tolower((unsigned char)start[i]);
            lowered[i] = '\0';
            if (strcmp(lowered, "stop") == 0) {
                printf("Exiting product input loop...\n");
                break;
            } else {
                printf("Product '%s' recorded.\n", start);
            }
        }
    }
    printf("Inventory input complete.\n");
    return 0;
}

