    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    string line;
    getline(cin, line); // consume end‑of‑line after T
    for (int tc = 0; tc < T; ++tc) {
        while (true) {
            if (!getline(cin, line)) return 0; // no more input
            // trim leading/trailing spaces
            size_t start = line.find_first_not_of(' ');
            size_t end = line.find_last_not_of(' ');
            string trimmed = (start == string::npos) ? "" : line.substr(start, end - start + 1);
            string lowered = trimmed;
            transform(lowered.begin(), lowered.end(), lowered.begin(), ::tolower);
            if (lowered == "stop") {
                cout << "Exiting product input loop...\n";
                break;
            } else {
                cout << "Product '" << trimmed << "' recorded.\n";
            }
        }
    }
    cout << "Inventory input complete.\n";
    return 0;
}

