#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(T):
        while idx < len(data):
            product = data[idx].strip()
            idx += 1
            if product.lower() == "stop":
                out.append("Exiting product input loop...")
                break
            else:
                out.append(f"Product '{product}' recorded.")
    out.append("Inventory input complete.")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

